using System.Collections.Generic;
using TMPro;
using UnityEngine;

/// <summary>
/// Mapa-Múndi (GDD "Nós e Painel Automático" / "Ramificações"): representa UM
/// nó do mapa-múndi — uma área (<see cref="area"/>) ou, para o caso especial
/// marcado por <see cref="isGaiaHub"/>, o Coração de Gaia.
///
/// Cada nó (excepto o Coração de Gaia) tem exactamente UMA ligação de origem
/// (<see cref="parentConnection"/>, vinda do nó mais próximo de Gaia) e zero ou
/// mais ligações de saída (<see cref="childConnections"/>, para os próximos
/// nós/ramificações). Esta estrutura em árvore, com o Coração de Gaia na raiz,
/// é a base de toda a lógica de "revelação de áreas e raízes" — ver
/// <see cref="WorldMapConnection"/> para a regra completa.
/// </summary>
public class WorldMapNode : MonoBehaviour
{
    [Header("Identidade")]
    [Tooltip("Área representada por este nó. Deixar vazio APENAS para o Coração de Gaia (marcar 'isGaiaHub').")]
    public AreaData area;

    [Tooltip("Marca este nó como o Coração de Gaia — hub central, sempre 'desbloqueado', sem painel de área normal (usa o HUD do Coração de Gaia em WorldMapUI).")]
    public bool isGaiaHub;

    [Header("Ligação de Origem")]
    [Tooltip("Ligação (ramo) que vem do nó-pai, mais próximo do Coração de Gaia. Deixar vazio APENAS para o Coração de Gaia.")]
    public WorldMapConnection parentConnection;

    [Header("Ligações de Saída")]
    [Tooltip("Ramos que partem deste nó para os próximos nós (filhos/ramificações). A ordem é usada como prioridade de desempate ao escolher a direcção com o analógico esquerdo quando há mais de uma opção igualmente alinhada.")]
    public List<WorldMapConnection> childConnections = new List<WorldMapConnection>();

    [Header("Visual — Estado do Nó")]
    [Tooltip("Activados quando a área está DESBLOQUEADA (ícone iluminado, cor do mundo, brilho, etc.).")]
    public GameObject[] unlockedVisuals;

    [Tooltip("Activados quando a área está BLOQUEADA mas ALCANÇÁVEL (cadeado/ícone escuro com custo visível — \"dá para chegar até aqui, mas não para atravessar\").")]
    public GameObject[] lockedVisuals;

    [Tooltip("Activados apenas enquanto este nó NÃO for alcançável (nem o ramo de origem está iluminado) — totalmente escondido/sombrio, sem nome nem custo visíveis.")]
    public GameObject[] hiddenVisuals;

    [Header("Rótulos (opcional)")]
    [Tooltip("Texto com o nome da área. Mostra \"?????????????\" enquanto bloqueada (a não ser que 'forceRevealName' esteja activo — Visão do Mapa-Múndi).")]
    public TMP_Text nameLabel;

    [Tooltip("Texto com o custo de desbloqueio (\"Custo: X Runas de Gaia\"). Visível apenas quando o nó está bloqueado mas alcançável (ou sempre, com 'forceRevealName').")]
    public TMP_Text costLabel;

    [Tooltip("Texto opcional usado pela 'Visão do Mapa-Múndi' para mostrar totais (\"Runas: X/Y\", \"NPCs: X/Y\", etc.) de uma área bloqueada, normalmente preenchido por WorldMapUI.")]
    public TMP_Text revealedInfoLabel;

    // -------------------- Estado --------------------

    /// <summary>Esta área já está desbloqueada (ou é o Coração de Gaia / um nó sem AreaData).</summary>
    public bool IsUnlocked
    {
        get
        {
            if (isGaiaHub || area == null) return true;

            var pp = PlayerProgress.Instance;
            return pp != null && pp.IsAreaUnlocked(area);
        }
    }

    /// <summary>
    /// O ramo até este nó está iluminado (nó-pai desbloqueado) — a bola PODE
    /// viajar até aqui mesmo que este nó continue bloqueado. O Coração de Gaia
    /// e nós já desbloqueados são sempre alcançáveis.
    /// </summary>
    public bool IsReachable => isGaiaHub || IsUnlocked || (parentConnection != null && parentConnection.IsLit);

    /// <summary>Custo em Runas de Gaia para desbloquear esta área (0 para Vilas, Boss, Coração de Gaia ou áreas já desbloqueadas).</summary>
    public int UnlockCost => (area != null && area.mapNodeType == AreaData.MapNodeType.Normal) ? Mathf.Max(0, area.unlockCost) : 0;

    /// <summary>Nome a mostrar quando desbloqueado/revelado.</summary>
    public string DisplayName => isGaiaHub ? "Coração de Gaia" : (area != null ? area.displayName : "");

    // -------------------- Visual --------------------

    /// <summary>
    /// Actualiza os objectos visuais e rótulos deste nó. "forceRevealName" é
    /// usado pela Visão do Mapa-Múndi (GDD): enquanto activo, mesmo nós
    /// bloqueados mostram o nome real e o custo (mas continuam bloqueados —
    /// esta visão não abre caminhos nem substitui o pagamento de Runas).
    /// </summary>
    public void RefreshVisual(bool forceRevealName = false)
    {
        bool unlocked = IsUnlocked;
        bool reachable = IsReachable;

        SetActiveAll(unlockedVisuals, unlocked);
        SetActiveAll(lockedVisuals, !unlocked && (reachable || forceRevealName));
        SetActiveAll(hiddenVisuals, !reachable && !forceRevealName);

        bool revealName = unlocked || forceRevealName;

        if (nameLabel != null)
            nameLabel.text = revealName ? DisplayName : "?????????????";

        if (costLabel != null)
        {
            bool showCost = !unlocked && (reachable || forceRevealName)
                            && area != null && area.mapNodeType == AreaData.MapNodeType.Normal;

            costLabel.gameObject.SetActive(showCost);
            if (showCost) costLabel.text = $"Custo: {UnlockCost} Runas de Gaia";
        }

        if (parentConnection != null) parentConnection.RefreshRootVisual();
        foreach (var conn in childConnections)
            if (conn != null) conn.RefreshRootVisual();
    }

    private static void SetActiveAll(GameObject[] objs, bool active)
    {
        if (objs == null) return;

        foreach (var go in objs)
            if (go != null) go.SetActive(active);
    }

    private void OnEnable() => RefreshVisual();

#if UNITY_EDITOR
    private void OnDrawGizmosSelected()
    {
        UnityEditor.Handles.Label(transform.position + Vector3.up * 0.5f, DisplayName);
    }
#endif
}
